  "questionProse": [
    "`<details>` 和 `<summary>` 在 HTML 中扮演什么角色？"
  ],
  "hintsProse": [],
  "explanationProse": [
    "[`<details>`](https://developer.mozilla.org/en-US/docs/Web/HTML/Element/details) 允许创建可折叠内容，[`<summary>`](https://developer.mozilla.org/en-US/docs/Web/HTML/Element/summary) 指定内容的可见标题。\n\n这对于常见问题解答、可折叠部分或任何可以切换的内容非常有用。"
  ]
}
